args.fn:
(fields) => {
  const set = (el, val) => {
    const proto = Object.getPrototypeOf(el);
    const setter = Object.getOwnPropertyDescriptor(proto, 'value').set;
    setter.call(el, val);
    el.dispatchEvent(new Event('input', { bubbles: true }));
    el.dispatchEvent(new Event('change', { bubbles: true }));
    el.dispatchEvent(new Event('blur', { bubbles: true }));
  };
  const results = {};
  for (const [name, value] of Object.entries(fields)) {
    const els = document.querySelectorAll(`[name="${CSS.escape(name)}"]`);
    if (!els.length) { results[name] = 'NOT_FOUND'; continue; }
    set(els[0], value);
    results[name] = 'OK:' + (value+'').slice(0, 40);
  }
  return results;
}

async (loc) => {
  if (!loc) return {skipped: 'no-location'};
  const inp = document.querySelector('#location-input, input.location-input');
  const sel = document.querySelector('#selected-location, input[name="selectedLocation"]');
  if (!inp || !sel) return {skipped: 'no-typeahead-on-page'};
  // First try the unauthenticated /searchLocations endpoint.
  try {
    const $ = window.jQuery || window.$;
    const hcap = ($ && $('#hcaptchaResponseInput').val()) || '';
    const res = await fetch('/searchLocations?text=' + encodeURIComponent(loc) + '&hcaptchaResponse=' + encodeURIComponent(hcap));
    const txt = await res.text();
    let locs = null;
    try { locs = JSON.parse(txt); } catch (_e) {}
    if (!locs || !locs.length) {
      // Fallback: stuff a synthetic object so the form has SOMETHING; Lever may
      // still reject server-side but we want submit to attempt rather than
      // silently no-op on blur-wipe.
      const proto = Object.getPrototypeOf(inp);
      const setter = Object.getOwnPropertyDescriptor(proto, 'value').set;
      setter.call(inp, loc);
      sel.value = JSON.stringify({name: loc});
      if ($) { $('input.location-input').off('blur'); }
      return {status: 'no-results-fallback', http: res.status, sample: txt.slice(0, 120)};
    }
    const lower = loc.toLowerCase();
    const target = locs.find(l => (l.name || '').toLowerCase() === lower)
                 || locs.find(l => (l.name || '').toLowerCase().startsWith(lower))
                 || locs[0];
    window.searchedLocations = locs;
    const proto = Object.getPrototypeOf(inp);
    const setter = Object.getOwnPropertyDescriptor(proto, 'value').set;
    setter.call(inp, target.name);
    sel.value = JSON.stringify(target);
    inp.dispatchEvent(new Event('input', {bubbles: true}));
    inp.dispatchEvent(new Event('change', {bubbles: true}));
    // Crucially: kill the blur-wipe handler so subsequent focus shifts don't
    // clear our values.
    if ($) { $('input.location-input').off('blur'); }
    return {status: 'OK', picked: target.name, id: target.id};
  } catch (e) {
    return {status: 'error', err: String(e).slice(0, 200)};
  }
}

(items) => {
  const results = [];
  for (const it of items) {
    const sel = document.querySelector(`select[name="${CSS.escape(it.name)}"]`);
    if (!sel) { results.push({name: it.name, status: 'NOT_FOUND'}); continue; }
    const want = (it.value+'').trim().toLowerCase();
    let chosen = null;
    for (const opt of sel.options) {
      const t = (opt.textContent || opt.value || '').trim().toLowerCase();
      if (t === want) { chosen = opt; break; }
    }
    if (!chosen) {
      for (const opt of sel.options) {
        const t = (opt.textContent || opt.value || '').trim().toLowerCase();
        if (t.includes(want) || want.includes(t)) { chosen = opt; break; }
      }
    }
    if (!chosen) { results.push({name: it.name, status: 'NO_MATCH', want: it.value}); continue; }
    sel.value = chosen.value;
    sel.dispatchEvent(new Event('change', { bubbles: true }));
    results.push({name: it.name, status: 'OK', picked: chosen.textContent.trim().slice(0,40)});
  }
  return results;
}

(items) => {
  const declines = (items.declines || []).map(s => s.toLowerCase());
  const results = [];
  // Process all eeo[*] fields automatically — covers anything we missed.
  const sels = document.querySelectorAll('select[name^="eeo["]');
  for (const sel of sels) {
    if (sel.value && sel.value !== '' && sel.value !== 'null') {
      results.push({name: sel.name, status: 'ALREADY_SET'}); continue;
    }
    let chosen = null;
    for (const opt of sel.options) {
      const t = (opt.textContent || '').trim().toLowerCase();
      if (declines.some(d => t.includes(d))) { chosen = opt; break; }
    }
    if (chosen) {
      sel.value = chosen.value;
      sel.dispatchEvent(new Event('change', { bubbles: true }));
      results.push({name: sel.name, status: 'OK', picked: chosen.textContent.trim()});
    } else {
      results.push({name: sel.name, status: 'NO_DECLINE_OPTION'});
    }
  }
  // Radio EEO fields: group by name.
  const allRadios = document.querySelectorAll('input[type="radio"][name^="eeo["]');
  const groups = {};
  for (const r of allRadios) { (groups[r.name] = groups[r.name] || []).push(r); }
  for (const [name, rs] of Object.entries(groups)) {
    if (rs.some(r => r.checked)) { results.push({name, status: 'ALREADY_SET'}); continue; }
    let picked = null;
    for (const r of rs) {
      let txt = '';
      let p = r.parentElement;
      while (p && !txt) { txt = (p.textContent || '').trim(); p = p.parentElement; if (txt.length > 200) break; }
      txt = txt.toLowerCase();
      if (declines.some(d => txt.includes(d))) { picked = r; break; }
    }
    if (picked) { picked.click(); results.push({name, status: 'OK', picked: picked.value}); }
    else { results.push({name, status: 'NO_DECLINE_OPTION'}); }
  }
  return results;
}

() => {
  const data = {};
  const inputs = document.querySelectorAll('#application-form input, #application-form textarea, #application-form select');
  for (const el of inputs) {
    if (!el.name) continue;
    if (el.type === 'file') { data[el.name] = el.files && el.files.length ? `FILE:${el.files[0].name}` : ''; continue; }
    if (el.type === 'checkbox' || el.type === 'radio') {
      if (el.checked) { data[el.name] = (data[el.name]||'') + '|' + el.value; }
      continue;
    }
    data[el.name] = (el.value || '').slice(0, 80);
  }
  return data;
}

args.detect_fn:
() => {
  // Common patterns:
  //   <div class="h-captcha" data-sitekey="...">
  //   <div data-hcaptcha-widget-id ... data-sitekey="...">
  //   <iframe src="https://newassets.hcaptcha.com/captcha/v1/.../hcaptcha.html#frame=challenge&id=...&sitekey=...">
  let sitekey = null;
  for (const el of document.querySelectorAll('[data-sitekey]')) {
    const candidate = el.getAttribute('data-sitekey');
    if (candidate && /^[0-9a-f-]{8,}$/i.test(candidate)) { sitekey = candidate; break; }
  }
  if (!sitekey) {
    for (const f of document.querySelectorAll('iframe[src*="hcaptcha.com"]')) {
      const m = (f.src || '').match(/[?&#]sitekey=([0-9a-f-]+)/i);
      if (m) { sitekey = m[1]; break; }
    }
  }
  const enclaves = document.querySelectorAll('iframe[src*="hcaptcha-enclave"]').length;
  const challenge = document.querySelectorAll('iframe[src*="hcaptcha.html"]').length;

  // hCaptcha ENTERPRISE rqdata extraction (2026-06-05). Enterprise/invisible
  // widgets generate per-session challenge data (`rqdata`) that MUST be passed
  // to the solver as enterprisePayload.rqdata, or the solved token is
  // valid-but-unbound and the apply-POST 400s (reproduced on FloQast +
  // PointClickCare, shared sitekey e33f87f8-...). Try several known carriers,
  // most-reliable first:
  let rqdata = null;
  try {
    // (a) data attribute on the widget container/iframe.
    for (const el of document.querySelectorAll('[data-hcaptcha-rqdata],[data-rqdata]')) {
      const v = el.getAttribute('data-hcaptcha-rqdata') || el.getAttribute('data-rqdata');
      if (v) { rqdata = v; break; }
    }
    // (b) captured render/execute config (set by the page-init hook below, if
    //     it ran before render: window.__hcaptchaRqData).
    if (!rqdata && window.__hcaptchaRqData) rqdata = window.__hcaptchaRqData;
    // (c) hCaptcha internal config blob: window.hcaptcha may expose the last
    //     render params; also scan a global config object some hosts set.
    if (!rqdata) {
      const blobs = [];
      try { if (window.hcaptcha && window.hcaptcha.getRespKey) blobs.push(window.hcaptcha); } catch(e){}
      for (const k of ['__hcaptchaConfig','hcaptchaConfig','rqdata']) {
        try { if (window[k]) blobs.push(window[k]); } catch(e){}
      }
      for (const b of blobs) {
        try {
          const s = JSON.stringify(b);
          const m = s && s.match(/"rqdata"\s*:\s*"([^"]+)"/);
          if (m) { rqdata = m[1]; break; }
        } catch(e){}
      }
    }
    // (d) last resort: scan inline <script> text for an rqdata string literal.
    if (!rqdata) {
      for (const sc of document.querySelectorAll('script:not([src])')) {
        const m = (sc.textContent || '').match(/["']rqdata["']\s*:\s*["']([^"']{16,})["']/);
        if (m) { rqdata = m[1]; break; }
      }
    }
  } catch (e) {}

  return {
    sitekey,
    page_url: location.href,
    enclaves,
    challenge_iframes: challenge,
    visible_challenge: challenge > 0,
    rqdata: rqdata || null,
    is_enterprise: !!rqdata,
  };
}

args.inject_fn:
(token) => {
  const setNative = (el, val) => {
    try {
      const proto = Object.getPrototypeOf(el);
      const setter = Object.getOwnPropertyDescriptor(proto, 'value');
      if (setter && setter.set) { setter.set.call(el, val); }
      else { el.value = val; }
    } catch (_e) { el.value = val; }
    el.dispatchEvent(new Event('input', { bubbles: true }));
    el.dispatchEvent(new Event('change', { bubbles: true }));
  };
  const selectors = [
    'textarea[name="h-captcha-response"]',
    'textarea[name="g-recaptcha-response"]',
    'textarea[id^="h-captcha-response"]',
    'textarea[id^="g-recaptcha-response"]',
    'input[name="h-captcha-response"]',
    'input[name="g-recaptcha-response"]',
  ];
  const seen = new Set();
  let found = 0;
  for (const sel of selectors) {
    for (const el of document.querySelectorAll(sel)) {
      if (seen.has(el)) continue;
      seen.add(el);
      found++;
      // Make hidden/zero-size textareas writable for React form libs that read
      // `.value` directly. We don't need them visible.
      if (el.style) {
        el.style.display = el.style.display === 'none' ? '' : el.style.display;
      }
      setNative(el, token);
    }
  }
  // Fire a global hCaptcha "verified" callback if present (some boards
  // register `window.hcaptcha._onVerify` or check `hcaptcha.getResponse()`).
  // We can't easily call internal callbacks, but setting the textarea is
  // sufficient for boards that read it on submit (Lever, Greenhouse, Ashby).
  return { found, set: found, token_len: (token || '').length };
}

